cancelPendingUpdate.solidity_pseudocode:
function cancelPendingUpdate(bytes32 updateId, bytes[] calldata sigs) external {
    PendingUpdate storage u = pendingUpdates[updateId];
    require(u.status == Status.Queued, 'Not queued');
    require(block.timestamp < u.queuedAt + 72 hours, 'Window closed — use new proposal');
    require(_verifyMultisig(sigs, keccak256(abi.encode('CANCEL', updateId)), 2), 'Insufficient sigs');
    u.status = Status.Cancelled;
    emit UpdateCancelled(updateId, block.timestamp);
}

