emergency_pause.solidity_pseudocode:
bool public paused;

function pause(bytes[] calldata sigs) external {
    require(_verifyMultisig(sigs, keccak256('PAUSE'), 2), 'Insufficient sigs');
    paused = true;
    emit ContractPaused(block.timestamp, msg.sender);
}

function unpause(bytes[] calldata sigs) external {
    require(_verifyMultisig(sigs, keccak256('UNPAUSE'), 3), 'Insufficient sigs');
    paused = false;
    emit ContractUnpaused(block.timestamp, msg.sender);
}

function verifyAndSettle(...) external {
    require(!paused, 'Contract paused — emergency halt active');
    // ... existing logic ...
}

